//! P4b object-intelligence — a CERTIFIED relative rigid-body dynamical profile per confirmed track.
//!
//! This lifts third-eye's object intelligence from {position, velocity, genus, rough mass} to a
//! profile that classifies each object's DYNAMICAL REGIME — at-rest / freely-translating /
//! freely-rotating / forced — by **which conservation laws hold** over the track's window. It is the
//! same admission discipline as `physics.rs` §7.5: each clause is `accept` / `abstain` / `decline`
//! and cites a green, Init-only, zero-axiom gnosis-math law. third-eye still runs NO force solver;
//! it reads the kinematic state the tracker + orientation-spinor already produce and ADMITS the
//! regime only when the relevant conservation law is satisfied within noise.
//!
//! HONEST BOUNDS (the load-bearing part of this module's contract):
//!  * EVERYTHING IS RELATIVE. There is no absolute SI scale: lengths are frame-normalised, mass is
//!    `density_guess * volume` with a coarse constant density, so masses/momenta/energies are only
//!    comparable WITHIN one scene (ratios), never absolute kg / J. The certified STRUCTURE — the
//!    regime label, the conservation verdicts, and the inter-object ratios — is the real output.
//!  * VOLUME / INERTIA are from the 2.5D extruded silhouette slab (recon::extrude), NOT a true 3D
//!    body. The moment of inertia reported is the IN-PLANE SPIN inertia (about the out-of-plane axis)
//!    because that is the only rotation a monocular silhouette can observe.
//!  * OUT-OF-PLANE angular velocity is NOT recoverable from one view (axis vs. foreshortening
//!    ambiguity). We report only in-plane ω, and ONLY when `OrientationSpinor::orientation_reliable`;
//!    otherwise the angular clause ABSTAINS (it never fabricates a spin).
//!
//! Laws pinned (all green, Init-only, zero-axiom; same provenance discipline as physics.rs):
//!  - momentum / angular-momentum conservation across a free window: `ForkRaceFoldVentAreForces.lean:49`
//!    `fork_preserves_charge` — branching/transport preserves the conserved total (here p and L are
//!    the transported conserved quantities). p ~ const over the window => "freely translating";
//!    L ~ const => "freely rotating / torque-free". A change beyond noise means an external force /
//!    torque acted: the conserved-quantity clause DECLINES "free" and the regime is "forced".
//!  - energy bookkeeping: `InformationConservation.lean:337` `information_conservation` — no free
//!    energy. Total KE (linear + rotational) must be accounted by the work the window can spend;
//!    a spontaneous KE increase with no source ABSTAINS the energy clause.
//!  - at-rest: `VacuumIsOnlyForce.lean:85` `vacuum_force_contracts` (reused from physics.rs).
//!  - causal velocity: `AckermannLightConeBridge.lean:183` `subluminal_never_reaches_front` (reused).

use crate::orientation_spinor::OrientationSpinor;
use crate::physics::Verdict;
use crate::recon::ObjectDescriptor;
use crate::track::Track;

/// Coarse relative density (uniform-material guess). Only the RATIO of masses across a scene is
/// meaningful; the absolute value is arbitrary and cancels in every regime test. Documented as a
/// guess so no downstream consumer mistakes `mass` for kilograms.
pub const DENSITY_GUESS: f32 = 1.0;

/// A per-object MATERIAL / MASS / INERTIA prior, supplied by the single-image reconstruction
/// (`apps/monster-studio/scripts/object-intel.mjs deriveObjectIntel`). This is the recon -> third-eye
/// half of the bidirectional feedback loop: the recon derives a ranked MATERIAL (by density/hardness),
/// a MASS (material density × solid voxel volume) and an INERTIA TENSOR from the real reconstructed
/// object geometry, and hands them here so third-eye's dynamics use REAL MATERIAL-WEIGHTED values
/// instead of the relative `DENSITY_GUESS = 1.0` (all-objects-equal-density) fallback.
///
/// HONEST SCALE (the load-bearing contract — see also the module header): the recon mass is
/// `density × volume` where volume is in NORMALISED / voxel units, with no absolute SI length. So what
/// a prior GROUNDS is the inter-object MASS RATIO (materially weighted: plastic vs. denser), NOT
/// absolute kilograms. A scene with priors reports momentum/energy as MATERIAL-GROUNDED RATIOS; a
/// scene without reports them RELATIVE-EQUAL-DENSITY; ABSOLUTE SI is ABSTAINED in both cases unless a
/// real scale reference is supplied (`scale_ref_cm`). The win is that the inter-object weighting — and
/// therefore the collision certification under real material differences — becomes correct, rather
/// than assuming every object has the same density.
#[derive(Debug, Clone, Copy)]
pub struct ObjectPrior {
    /// MATERIAL DENSITY from the recon (g/cm³ in the recon's table; used here as a RELATIVE weight —
    /// only the ratio between objects is load-bearing, never the absolute g/cm³). Replaces
    /// `DENSITY_GUESS` when present, so `mass = density × volume` is material-weighted.
    pub density: f32,
    /// The recon's top-ranked material name (e.g. "plastic", "metal (steel)"). Carried for reporting
    /// and to pick the restitution prior (plastic/metal/rubber bounce differently).
    pub material: MaterialKind,
    /// Optional recon-provided in-plane spin inertia (relative units). When `Some`, it OVERRIDES the
    /// silhouette-derived `inertia_spin` (the recon's true 3D voxel inertia is better than the 2.5D
    /// lamina estimate). When `None`, the silhouette inertia is kept but re-weighted by the material
    /// density (so L = I·ω is still material-grounded).
    pub inertia: Option<f32>,
    /// Optional ABSOLUTE scale reference: the real-world length (cm) of the object's longest extent.
    /// Supplied ONLY when a measurement / in-frame reference exists. When present the scene MAY report
    /// absolute SI; when absent (the default) absolute SI is ABSTAINED and only ratios are grounded.
    pub scale_ref_cm: Option<f32>,
}

/// The coarse material class a prior carries — enough to pick a restitution (bounce) prior and to
/// report the material weighting. Maps the recon's ranked-material string onto a small closed set.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum MaterialKind {
    /// Hard, high-restitution (steel, aluminium): a bounce conserves most KE => elastic-leaning.
    Metal,
    /// Hard, brittle vessels (glass, ceramic, stoneware, stone): fairly elastic when intact.
    Ceramic,
    /// Mid restitution (plastics).
    Plastic,
    /// High-loss, deformable (rubber, soft): a contact dissipates KE => inelastic-leaning.
    Rubber,
    /// High-loss, soft (wood, paper, cardboard): largely inelastic.
    Soft,
    /// Unrecognised / unranked material: no restitution prior, fall back to the KE-delta only.
    Unknown,
}

impl MaterialKind {
    /// Map a recon material-name string onto the closed material set (matches the names in
    /// `object-intel.mjs`'s MATERIALS table; tolerant of substrings).
    pub fn from_name(name: &str) -> MaterialKind {
        let n = name.to_ascii_lowercase();
        if n.contains("metal") || n.contains("steel") || n.contains("aluminum") || n.contains("aluminium") {
            MaterialKind::Metal
        } else if n.contains("glass") || n.contains("ceramic") || n.contains("porcelain") || n.contains("stoneware") || n.contains("stone") || n.contains("clay") {
            MaterialKind::Ceramic
        } else if n.contains("plastic") {
            MaterialKind::Plastic
        } else if n.contains("rubber") {
            MaterialKind::Rubber
        } else if n.contains("wood") || n.contains("paper") || n.contains("cardboard") {
            MaterialKind::Soft
        } else {
            MaterialKind::Unknown
        }
    }

    pub fn as_str(self) -> &'static str {
        match self {
            MaterialKind::Metal => "metal",
            MaterialKind::Ceramic => "ceramic",
            MaterialKind::Plastic => "plastic",
            MaterialKind::Rubber => "rubber",
            MaterialKind::Soft => "soft",
            MaterialKind::Unknown => "unknown",
        }
    }

    /// A coefficient-of-restitution PRIOR for a contact dominated by this material (0 = perfectly
    /// inelastic stick, 1 = perfectly elastic bounce). Coarse, material-grounded, RELATIVE — it sets
    /// the EXPECTED elastic/inelastic leaning that the measured KE delta is then read against; it does
    /// NOT override the measurement. `None` for `Unknown` (defer entirely to the KE delta).
    pub fn restitution_prior(self) -> Option<f32> {
        match self {
            MaterialKind::Metal => Some(0.80),
            MaterialKind::Ceramic => Some(0.70),
            MaterialKind::Plastic => Some(0.55),
            MaterialKind::Rubber => Some(0.40),
            MaterialKind::Soft => Some(0.20),
            MaterialKind::Unknown => None,
        }
    }
}

/// The certified dynamical regime of an object — the net verdict over the conservation clauses.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Regime {
    /// Speed low and monotonically contracting (vacuum_force_contracts).
    AtRest,
    /// Linear momentum conserved over the window (fork_preserves_charge) and not at rest.
    FreeTranslation,
    /// Angular momentum conserved over the window (fork_preserves_charge), torque-free spin.
    FreeRotation,
    /// A conserved quantity (p and/or L) changed beyond noise — an external force/torque acted.
    Forced,
    /// Not enough evidence to certify any regime (unreliable lift, too-short window, low confidence).
    Abstain,
}

impl Regime {
    pub fn as_str(self) -> &'static str {
        match self {
            Regime::AtRest => "at_rest",
            Regime::FreeTranslation => "free_translation",
            Regime::FreeRotation => "free_rotation",
            Regime::Forced => "forced",
            Regime::Abstain => "abstain",
        }
    }
}

/// WHY a regime is not a clean free-body certification — an INFORMATIVE annotation on an `Abstain`
/// (or `Forced`) verdict. This NEVER changes the regime decision; it reads the SAME quantities the
/// admission already computed (momentum spread, hold frames, the angular/lift facts) and reports the
/// most likely cause, so a deforming hand reads "non-rigid/actuated" instead of bare "abstain".
///
/// HONEST: this is a classification of the FAILURE MODE, not a new physics certificate. It says which
/// rigid-body assumption broke, not what the object IS. A `NonRigidActuated` read maps to "the
/// momentum spread is far beyond the rigid tolerance and the body is not approaching rest" — the
/// kinematic signature a deformable / muscle-actuated body produces; it is not a claim that the body
/// is a hand, only that it is not behaving as a free rigid body.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum AbstainReason {
    /// Not abstaining — the regime is a clean free/at-rest/forced certification needing no annotation.
    None,
    /// Momentum (and/or angular momentum) spread FAR exceeds the rigid tolerance while the body is
    /// moving and NOT approaching rest: a deforming / actuated body (a grabbing hand, a flexing limb).
    /// The conserved-quantity test fails not because of one external impulse but because no single
    /// rigid momentum exists over the window.
    NonRigidActuated,
    /// A clean SINGLE force event: momentum changed beyond noise but the spread is near the rigid
    /// tolerance band (an impulse, not chaos). The regime is `Forced`; this names it as resolvable.
    Forced,
    /// Too few held frames / low confidence to decide anything: the evidence window is too short.
    Unresolved,
    /// Tracking gap, Nyquist alias, or an unreliable in-plane lift (out-of-plane / monocular):
    /// the measurement itself is unreliable, so no regime can be read.
    AliasedUnreliable,
}

impl AbstainReason {
    pub fn as_str(self) -> &'static str {
        match self {
            AbstainReason::None => "none",
            AbstainReason::NonRigidActuated => "non_rigid_actuated",
            AbstainReason::Forced => "forced",
            AbstainReason::Unresolved => "unresolved",
            AbstainReason::AliasedUnreliable => "aliased_unreliable",
        }
    }

    /// A short human phrase for the per-object headline, e.g. "non-rigid/actuated (not a free rigid body)".
    pub fn phrase(self) -> &'static str {
        match self {
            AbstainReason::None => "free-body regime certified",
            AbstainReason::NonRigidActuated => "non-rigid/actuated (not a free rigid body)",
            AbstainReason::Forced => "a single force event (resolvable)",
            AbstainReason::Unresolved => "unresolved (too few held frames / low confidence)",
            AbstainReason::AliasedUnreliable => "aliased/unreliable (tracking gap or out-of-plane lift)",
        }
    }
}

/// One clause of the dynamical admission, mirroring `physics::FactVerdict`.
#[derive(Debug, Clone)]
pub struct DynVerdict {
    pub fact: &'static str,
    pub verdict: Verdict,
    pub law: &'static str,
    pub reason: String,
}

/// The relative rigid-body dynamical profile of one confirmed track.
#[derive(Debug, Clone)]
pub struct RigidProfile {
    pub id: u64,
    pub genus: u32,

    // --- geometry (relative, 2.5D) ---
    /// Silhouette area fraction of the bbox times bbox area (normalised silhouette area, 0..~1).
    pub silhouette_area: f32,
    /// Characteristic size = geometric mean of bbox sides (normalised).
    pub char_size: f32,
    /// Slab thickness used for the 2.5D extrusion (recon depth heuristic).
    pub depth: f32,
    /// Relative volume = silhouette_area * depth.
    pub volume: f32,
    /// Material-weighted mass = density * volume. `density` is the recon MATERIAL density when a
    /// prior was supplied (material-grounded ratio across the scene), else `DENSITY_GUESS` (relative
    /// equal-density). See `grounded`.
    pub mass: f32,
    /// The density used for `mass`: the recon material density (when `grounded`) or `DENSITY_GUESS`.
    pub density: f32,
    /// The material weighting this object's mass/inertia was grounded with. `Unknown` (and
    /// `grounded == false`) when no prior was supplied — the relative equal-density fallback.
    pub material: MaterialKind,
    /// True when a recon MATERIAL/MASS/INERTIA prior grounded this profile (mass = material_density ×
    /// volume; inertia material-weighted). False => relative equal-density (`DENSITY_GUESS`).
    pub grounded: bool,
    /// In-plane spin moment of inertia about the out-of-plane axis: mass * (Ixx+Iyy)-style second
    /// moment of the silhouette (relative units). This is I_zz for the planar lamina.
    pub inertia_spin: f32,

    // --- linear state ---
    pub vx: f32,
    pub vy: f32,
    pub speed: f32,
    /// |p| = mass * speed (relative).
    pub momentum: f32,
    /// linear kinetic energy = 1/2 m |v|^2 (relative).
    pub ke_lin: f32,

    // --- angular state (None when the spinor lift is unreliable: out-of-plane / monocular abstain) ---
    /// In-plane angular velocity ω (rad/s), from d(director_unwrapped)/dt. None => abstain.
    pub omega: Option<f32>,
    /// angular momentum L = I * ω (relative). None when ω abstains.
    pub ang_momentum: Option<f32>,
    /// rotational KE = 1/2 I ω^2 (relative). None when ω abstains.
    pub ke_rot: Option<f32>,

    // --- certification ---
    pub regime: Regime,
    pub facts: Vec<DynVerdict>,

    // --- informative-abstain annotation (does NOT change the regime; see AbstainReason) ---
    /// Linear-momentum spread fraction (max-min)/|mean| over the window — the raw quantity the
    /// momentum_conserved clause tested. Used by the abstain-reason classifier. f32::INFINITY when
    /// the window was too short to measure.
    pub momentum_spread: f32,
    /// Angular-momentum spread fraction over the window, or None when the in-plane lift abstains.
    pub ang_spread: Option<f32>,
    /// Frames the conservation window actually held (matched trajectory points used) — the evidence
    /// depth behind the regime verdict.
    pub hold_frames: usize,
    /// WHY the regime is not a clean free-body certification (informative annotation on Abstain/Forced).
    pub abstain_reason: AbstainReason,
}

/// Tunables for the dynamical regime tests. Defaults are conservative (favour abstain over a wrong
/// certification).
#[derive(Debug, Clone)]
pub struct IntelConfig {
    /// Below this speed (normalised u/s) a candidate is "at rest" if contracting.
    pub rest_speed: f32,
    /// Window length (matched samples) over which conservation is tested. Need at least this many
    /// to decide anything; otherwise abstain (no free trajectory without evidence).
    pub window: usize,
    /// Relative tolerance (fraction of the window-mean) within which a conserved quantity counts as
    /// "constant". A spread above this is "changing" => forced.
    pub conserve_tol: f32,
    /// Minimum |ω| (rad/s) to call a track "rotating" at all (below this, rotation is noise).
    pub omega_min: f32,
    /// Minimum confidence (hits/(hits+misses)) to certify any regime (information_conservation).
    pub min_confidence: f32,
    /// Multiple of `conserve_tol` above which a momentum/angular spread is "FAR beyond" the rigid
    /// band — the non-rigid/actuated threshold for the informative-abstain classifier. A spread above
    /// `non_rigid_factor * conserve_tol` on a moving, not-settling body reads as deforming/actuated
    /// (no single rigid momentum over the window), vs a single clean impulse near the band. Pure
    /// annotation; does NOT change any regime decision.
    pub non_rigid_factor: f32,
}

impl Default for IntelConfig {
    fn default() -> Self {
        IntelConfig {
            rest_speed: 0.02,
            window: 6,
            conserve_tol: 0.25,
            omega_min: 0.15,
            min_confidence: 0.6,
            non_rigid_factor: 4.0,
        }
    }
}

fn confidence(t: &Track) -> f32 {
    let denom = (t.hits + t.misses).max(1) as f32;
    t.hits as f32 / denom
}

/// Second moment of the silhouette about the out-of-plane axis (I_zz of a planar lamina), in
/// normalised area·length² units, derived from the descriptor's principal variances. `describe`
/// gives elongation = sqrt(λ_maj/λ_min) and orientation; the absolute variances are not exported, so
/// we reconstruct a relative I_zz = (λ_maj + λ_min) shape factor scaled by the characteristic size².
///
/// We use char_size² as the relative scale (the silhouette spans ~char_size) and the elongation to
/// split the in-plane spread: a more elongated body has larger I_zz for the same size (mass further
/// from the spin axis along the major axis). I_zz_shape = (e² + 1) / (2 e) is the normalised ratio of
/// the lamina's mean-square radius to the round-disc case, a monotone-in-elongation factor (=1 at
/// e=1). RELATIVE only — see module header.
fn izz_shape_factor(elongation: f32) -> f32 {
    let e = elongation.max(1.0);
    // mean-square radius of an ellipse ∝ a² + b² with a/b = e; normalise so a round disc (e=1) -> 1.
    // a²+b² ∝ e² + 1, and the round case a=b gives 2; geometric size held fixed via a*b. Scaling by
    // 1/(2e) keeps area (∝ a*b) fixed as e grows, isolating the spread effect.
    (e * e + 1.0) / (2.0 * e)
}

/// Average in-plane angular velocity (rad/s) over the track, from the spinor lift. Returns None when
/// the lift is unreliable (Nyquist alias / ill-defined axis) — the out-of-plane / monocular abstain.
/// Uses the track's matched-time span (last_pts - first trajectory pts) as the elapsed time.
fn omega_from_spinor(sp: &OrientationSpinor, dt_total: f32) -> Option<f32> {
    if !sp.orientation_reliable || sp.samples < 2 || dt_total <= 1e-3 {
        return None;
    }
    // director_unwrapped accumulates the continuous director angle; its rate is the in-plane spin ω.
    // (director winding * 2π / time = the physical angular rate, since one director turn = one
    // physical turn for the in-plane lift.)
    let total_angle = sp.director_unwrapped - sp.history.first().map(|h| h.0).unwrap_or(0.0);
    Some(total_angle / dt_total)
}

/// Per-window samples of a scalar conserved quantity, with a "constancy" test. Returns
/// (mean, spread_fraction, is_constant). `spread_fraction` = (max-min)/|mean| over the window.
fn constancy(samples: &[f32], tol: f32) -> (f32, f32, bool) {
    if samples.is_empty() {
        return (0.0, f32::INFINITY, false);
    }
    let mean = samples.iter().sum::<f32>() / samples.len() as f32;
    let (mut lo, mut hi) = (f32::INFINITY, f32::NEG_INFINITY);
    for &s in samples {
        lo = lo.min(s);
        hi = hi.max(s);
    }
    let denom = mean.abs().max(1e-6);
    let spread = (hi - lo) / denom;
    (mean, spread, spread <= tol)
}

/// Linear momentum magnitude over the recent window: |p_k| = m * |v_k| where v_k is the
/// finite-difference velocity between consecutive trajectory points. Returns the window series.
fn momentum_window(t: &Track, mass: f32, window: usize) -> Vec<f32> {
    let n = t.trajectory.len();
    if n < 2 {
        return Vec::new();
    }
    let start = n.saturating_sub(window + 1);
    let mut out = Vec::new();
    for k in (start + 1)..n {
        let (t1, x1, y1) = t.trajectory[k];
        let (t0, x0, y0) = t.trajectory[k - 1];
        let dt = (t1 - t0).max(1e-3) as f32;
        let v = (((x1 - x0).powi(2) + (y1 - y0).powi(2)).sqrt()) / dt;
        out.push(mass * v);
    }
    out
}

/// Per-sample angular momentum L = I * ω_k over the spinor history window, where ω_k is the
/// per-step director increment scaled by the mean step time. Samples are assumed ~evenly spaced in
/// time (a steadily-matched track). Returns None when the lift is unreliable.
fn ang_momentum_window(
    sp: &OrientationSpinor,
    inertia: f32,
    dt_total: f32,
    window: usize,
) -> Option<Vec<f32>> {
    if !sp.orientation_reliable || sp.history.len() < 2 || dt_total <= 1e-3 {
        return None;
    }
    let hist = &sp.history;
    let n = hist.len();
    // Mean inter-sample time over the whole matched span (history carries no per-sample pts).
    let dt_step = (dt_total / (n.saturating_sub(1).max(1)) as f32).max(1e-3);
    let start = n.saturating_sub(window + 1);
    let mut out = Vec::new();
    for k in (start + 1)..n {
        let dtheta = hist[k].0 - hist[k - 1].0; // director_unwrapped increment
        let omega_k = dtheta / dt_step;
        out.push(inertia * omega_k);
    }
    Some(out)
}

const LAW_CONSERVE: &str = "ForkRaceFoldVentAreForces.fork_preserves_charge";
const LAW_ENERGY: &str = "InformationConservation.information_conservation";
const LAW_REST: &str = "VacuumIsOnlyForce.vacuum_force_contracts";
const LAW_CAUSAL: &str = "AckermannLightConeBridge.subluminal_never_reaches_front";

/// Build the certified relative rigid-body dynamical profile for a confirmed track, with NO recon
/// prior (relative equal-density: `mass = DENSITY_GUESS × volume`). Convenience wrapper over
/// [`profile_with_prior`].
pub fn profile(t: &Track, desc: &ObjectDescriptor, depth: f32, c_max: f32, cfg: &IntelConfig) -> RigidProfile {
    profile_with_prior(t, desc, depth, c_max, cfg, None)
}

/// Build the certified rigid-body dynamical profile for a confirmed track, GROUNDED by an optional
/// recon MATERIAL/MASS/INERTIA prior.
///
/// `desc` is the descriptor of the track's most-recent matched silhouette (elongation/aspect/fill),
/// `depth` the recon extrusion depth used for the volume. `prior`, when `Some`, supplies the recon
/// MATERIAL DENSITY (so `mass = density_material × volume` — material-weighted) and optionally the
/// recon inertia, replacing the `DENSITY_GUESS = 1.0` relative-only mass. The geometry is relative
/// (see header); a prior grounds the inter-object MASS RATIO, not absolute SI.
pub fn profile_with_prior(
    t: &Track,
    desc: &ObjectDescriptor,
    depth: f32,
    c_max: f32,
    cfg: &IntelConfig,
    prior: Option<&ObjectPrior>,
) -> RigidProfile {
    let mut facts = Vec::new();

    // --- geometry (relative, 2.5D) ---
    // Silhouette area (normalised) = fill (silhouette/bbox) * bbox area. bbox sides are normalised.
    let bbox_area = (t.bw * t.bh).max(1e-9);
    let silhouette_area = (desc.fill * bbox_area).max(1e-9);
    let char_size = (t.bw * t.bh).max(1e-12).sqrt();
    let volume = silhouette_area * depth;
    // MATERIAL-GROUNDED MASS: with a recon prior, mass = material_density × volume (so a small dense
    // object and a big light one are weighted by their REAL material ratio); without, fall back to the
    // relative equal-density guess. Only the inter-object ratio is grounded (volume is in normalised
    // units — no absolute SI; see ObjectPrior).
    let (density, material, grounded) = match prior {
        Some(p) if p.density > 0.0 => (p.density, p.material, true),
        _ => (DENSITY_GUESS, MaterialKind::Unknown, false),
    };
    let mass = density * volume;
    // I_zz of the planar lamina (relative): mass * char_size² * shape(elongation). When the recon
    // supplied a true (voxel) inertia, use it (re-scaled by the material mass so the units match the
    // material-weighted mass); else keep the silhouette inertia (already material-weighted via mass).
    let inertia_spin = match prior.and_then(|p| p.inertia) {
        Some(i_recon) if i_recon > 0.0 => i_recon,
        _ => mass * char_size * char_size * izz_shape_factor(desc.elongation),
    };

    // --- linear state ---
    let (vx, vy) = (t.vx(), t.vy());
    let speed = t.speed();
    let momentum = mass * speed;
    let ke_lin = 0.5 * mass * speed * speed;

    // --- causal-velocity gate (reuse the lightcone law) ---
    let v_verdict = if speed > c_max { Verdict::Decline } else { Verdict::Accept };
    facts.push(DynVerdict {
        fact: "velocity_causal",
        verdict: v_verdict,
        law: LAW_CAUSAL,
        reason: format!("|v|={:.3} vs c_max={:.3}", speed, c_max),
    });

    // --- existence / confidence gate (reuse information_conservation) ---
    let conf = confidence(t);
    let exists = t.confirmed && conf >= cfg.min_confidence;
    facts.push(DynVerdict {
        fact: "exists_known",
        verdict: if exists { Verdict::Accept } else { Verdict::Abstain },
        law: LAW_ENERGY,
        reason: format!("confidence={:.2} (hits {} misses {})", conf, t.hits, t.misses),
    });

    // --- angular state from the spinor lift (monocular: out-of-plane abstains) ---
    let dt_total = {
        let traj = &t.trajectory;
        if traj.len() >= 2 {
            (traj.last().unwrap().0 - traj.first().unwrap().0) as f32
        } else {
            0.0
        }
    };
    let omega = omega_from_spinor(&t.spinor, dt_total);
    let (ang_momentum, ke_rot) = match omega {
        Some(w) => (Some(inertia_spin * w), Some(0.5 * inertia_spin * w * w)),
        None => (None, None),
    };

    // ================= REGIME CLASSIFICATION via conservation =================

    // 1. AT REST (vacuum_force_contracts): low speed AND monotonically contracting. (The fact is
    //    pushed after the angular clause so a demonstrated spin can downgrade it — a spinning body
    //    with a fixed centroid is NOT at rest.)
    let at_rest_centroid = speed < cfg.rest_speed && speed_contracting(t, cfg.window);

    // 2. MOMENTUM CONSERVATION (fork_preserves_charge): |p| ~ const over the window => free transl.
    let p_win = momentum_window(t, mass, cfg.window);
    let hold_frames = p_win.len();
    let mut p_conserved = false;
    let mut momentum_spread = f32::INFINITY;
    if p_win.len() >= cfg.window.min(2) {
        let (p_mean, p_spread, p_const) = constancy(&p_win, cfg.conserve_tol);
        momentum_spread = p_spread;
        p_conserved = p_const && !at_rest_centroid && speed >= cfg.rest_speed;
        let verdict = if speed < cfg.rest_speed {
            // At/near rest the momentum is trivially ~0 (conserved-trivial); the spread ratio
            // (max-min)/mean blows up on pure noise around zero, so it carries NO force signal here.
            // Defer to the at_rest (vacuum_force_contracts) clause — abstain, never DECLINE on noise.
            Verdict::Abstain
        } else if p_const {
            Verdict::Accept
        } else {
            // changing momentum on a MOVING track => an external force acted => "forced".
            Verdict::Decline
        };
        facts.push(DynVerdict {
            fact: "momentum_conserved",
            verdict,
            law: LAW_CONSERVE,
            reason: format!(
                "|p|_mean={:.4} spread={:.1}% over {} pts (tol {:.0}%)",
                p_mean, p_spread * 100.0, p_win.len(), cfg.conserve_tol * 100.0
            ),
        });
    } else {
        facts.push(DynVerdict {
            fact: "momentum_conserved",
            verdict: Verdict::Abstain,
            law: LAW_CONSERVE,
            reason: format!("window too short ({} < {} pts)", p_win.len(), cfg.window),
        });
    }

    // 3. ANGULAR-MOMENTUM CONSERVATION (fork_preserves_charge): L ~ const => free rotation.
    //    The NEW gate the orientation-spinor unlocks. Abstains when the lift is unreliable
    //    (out-of-plane / monocular / Nyquist alias) — never fabricates a spin.
    let mut l_conserved = false;
    let mut rotating = false;
    let mut ang_spread: Option<f32> = None;
    match ang_momentum_window(&t.spinor, inertia_spin, dt_total, cfg.window) {
        Some(l_win) if l_win.len() >= cfg.window.min(2) => {
            let (l_mean, l_spread, l_const) = constancy(&l_win, cfg.conserve_tol);
            ang_spread = Some(l_spread);
            let w = omega.unwrap_or(0.0);
            rotating = w.abs() >= cfg.omega_min;
            l_conserved = l_const && rotating;
            let verdict = if !rotating {
                Verdict::Abstain // not spinning fast enough to test torque-free spin
            } else if l_const {
                Verdict::Accept
            } else {
                Verdict::Decline // L changing on a spinning body => a torque acted
            };
            facts.push(DynVerdict {
                fact: "angular_momentum_conserved",
                verdict,
                law: LAW_CONSERVE,
                reason: format!(
                    "L_mean={:.4} spread={:.1}% ω={:+.3} rad/s over {} pts (tol {:.0}%)",
                    l_mean, l_spread * 100.0, w, l_win.len(), cfg.conserve_tol * 100.0
                ),
            });
        }
        _ => {
            facts.push(DynVerdict {
                fact: "angular_momentum_conserved",
                verdict: Verdict::Abstain,
                law: LAW_CONSERVE,
                reason: if t.spinor.orientation_reliable {
                    "window too short for L test".to_string()
                } else {
                    "in-plane lift unreliable (out-of-plane/monocular): ω abstains".to_string()
                },
            });
        }
    }

    // AT-REST fact (pushed now that `rotating` is known): a fixed/contracting centroid is at rest
    // ONLY if it is not also demonstrably spinning. A torque-free spinner has a still centroid but
    // is freely rotating, not at rest.
    let at_rest = at_rest_centroid && !rotating;
    if speed < cfg.rest_speed {
        facts.push(DynVerdict {
            fact: "at_rest",
            verdict: if at_rest {
                Verdict::Accept
            } else if rotating {
                Verdict::Abstain
            } else {
                Verdict::Abstain
            },
            law: LAW_REST,
            reason: if at_rest {
                format!("|v|={:.3} contracting over {} pts, not spinning", speed, cfg.window)
            } else if rotating {
                format!("|v|={:.3} centroid still but body is spinning (ω={:+.3}) => not at rest", speed, omega.unwrap_or(0.0))
            } else {
                format!("|v|={:.3} low but not contracting (jitter)", speed)
            },
        });
    }

    // 4. ENERGY BOOKKEEPING (information_conservation): total KE accounted, no free energy. We hold
    //    this as a consistency abstain-or-accept: a spontaneously GROWING total KE on a free
    //    (no-force) window is unaccounted energy => abstain the energy clause. Within a conserved
    //    (free) window total KE should be ~flat; growth there is the contradiction.
    let ke_total = ke_lin + ke_rot.unwrap_or(0.0);
    let energy_ok = energy_accounted(t, mass, inertia_spin, omega, dt_total, cfg.window);
    facts.push(DynVerdict {
        fact: "energy_accounted",
        verdict: if energy_ok { Verdict::Accept } else { Verdict::Abstain },
        law: LAW_ENERGY,
        reason: format!(
            "KE_total(rel)={:.5} (lin {:.5} + rot {:.5}); {}",
            ke_total,
            ke_lin,
            ke_rot.unwrap_or(0.0),
            if energy_ok { "no unaccounted gain" } else { "spontaneous KE gain (held)" }
        ),
    });

    // ================= NET REGIME =================
    let regime = if v_verdict == Verdict::Decline || !exists {
        // Can't even certify the object is real/causal — no dynamical claim.
        Regime::Abstain
    } else if l_conserved {
        // A torque-free spinner can have a still centroid; a demonstrated conserved spin means the
        // body is FREELY ROTATING, not at rest — the angular clause overrides the at-rest centroid
        // test (a fixed centroid is necessary but not sufficient for at-rest once L is non-zero).
        Regime::FreeRotation
    } else if at_rest {
        Regime::AtRest
    } else if !energy_ok {
        // Unaccounted energy: hold the whole dynamical verdict rather than mislabel.
        Regime::Abstain
    } else {
        // Decide free vs forced from the conservation clauses. A free clause that PASSED wins; a
        // conservation clause that DECLINED (changed beyond noise) means a force/torque acted.
        let p_changed = facts
            .iter()
            .any(|f| f.fact == "momentum_conserved" && f.verdict == Verdict::Decline);
        let l_changed = facts
            .iter()
            .any(|f| f.fact == "angular_momentum_conserved" && f.verdict == Verdict::Decline);
        if p_conserved {
            Regime::FreeTranslation
        } else if p_changed || l_changed {
            Regime::Forced
        } else {
            // Moving but neither free nor demonstrably forced (e.g. window too short, ω abstains and
            // p inconclusive): honest abstain.
            Regime::Abstain
        }
    };

    // ============ INFORMATIVE-ABSTAIN ANNOTATION (does NOT touch the regime) ============
    let abstain_reason = classify_abstain(
        regime,
        speed,
        conf,
        exists,
        v_verdict,
        momentum_spread,
        ang_spread,
        hold_frames,
        at_rest_centroid,
        &t.spinor,
        cfg,
    );

    RigidProfile {
        id: t.id,
        genus: t.genus,
        silhouette_area,
        char_size,
        depth,
        volume,
        mass,
        density,
        material,
        grounded,
        inertia_spin,
        vx,
        vy,
        speed,
        momentum,
        ke_lin,
        omega,
        ang_momentum,
        ke_rot,
        regime,
        facts,
        momentum_spread,
        ang_spread,
        hold_frames,
        abstain_reason,
    }
}

/// Classify WHY a regime is not a clean free-body certification, from the SAME quantities the
/// admission already computed. Pure annotation — see [`AbstainReason`]. Order of precedence:
///   1. A clean free/at-rest regime => `None` (nothing to annotate).
///   2. Unreliable measurement first (causal decline, low confidence, too-short window, alias).
///   3. `Forced` regime => `Forced` (a single resolvable force event).
///   4. Abstain with momentum (or L) spread FAR beyond the rigid tolerance while moving and not
///      approaching rest => `NonRigidActuated` (deforming/actuated body — no single rigid momentum).
///   5. Otherwise `Unresolved` (moving but inconclusive within the window).
///
/// The "far beyond" threshold is `non_rigid_factor` * conserve_tol (default 4x the 25% rigid band =
/// a ~100% spread), the regime where a body's instantaneous momentum has no rigid mean over the
/// window — the kinematic fingerprint of deformation/actuation, distinct from a single clean impulse.
#[allow(clippy::too_many_arguments)]
fn classify_abstain(
    regime: Regime,
    speed: f32,
    conf: f32,
    exists: bool,
    v_verdict: Verdict,
    momentum_spread: f32,
    ang_spread: Option<f32>,
    hold_frames: usize,
    at_rest_centroid: bool,
    spinor: &OrientationSpinor,
    cfg: &IntelConfig,
) -> AbstainReason {
    // Clean free/at-rest certifications carry no annotation.
    if matches!(regime, Regime::AtRest | Regime::FreeTranslation | Regime::FreeRotation) {
        return AbstainReason::None;
    }

    // From here the regime is Abstain OR Forced — both warrant a "why". Measurement-unreliable causes
    // take precedence over a dynamical read.
    if v_verdict == Verdict::Decline {
        return AbstainReason::AliasedUnreliable; // superluminal jump => association/tracking error
    }
    if !exists || conf < cfg.min_confidence {
        return AbstainReason::Unresolved; // not confidently a real, persistent object yet
    }
    if hold_frames < cfg.window.min(2) {
        return AbstainReason::Unresolved; // window too short to test conservation at all
    }

    // The non-rigid / actuated fingerprint: a MOVING body, not approaching rest, whose momentum
    // spread is FAR beyond the rigid tolerance (and/or whose angular spread is). No single rigid
    // momentum exists over the window — the signature of deformation / muscle actuation. This is
    // checked BEFORE the single-force read because a deforming body can NET to either `Forced` (a
    // lone DECLINE) or `Abstain` (DECLINE + an unaccounted-energy hold); in both cases a spread far
    // beyond the band means there is no single rigid momentum, distinct from one clean impulse.
    let far = cfg.non_rigid_factor * cfg.conserve_tol;
    let moving_not_settling = speed >= cfg.rest_speed && !at_rest_centroid;
    let p_chaotic = momentum_spread.is_finite() && momentum_spread > far;
    let l_chaotic = ang_spread.map(|s| s > far).unwrap_or(false);
    if moving_not_settling && (p_chaotic || l_chaotic) {
        return AbstainReason::NonRigidActuated;
    }

    // A `Forced` regime with a spread NEAR the rigid band (not chaotic) is one clean, resolvable
    // force event.
    if regime == Regime::Forced {
        return AbstainReason::Forced;
    }

    // Abstain with a reliable-enough body but inconclusive: an unreliable lift on a still-ish body
    // reads as aliased/unreliable; otherwise the window simply didn't resolve a regime.
    if !spinor.orientation_reliable && speed < cfg.rest_speed {
        return AbstainReason::AliasedUnreliable;
    }

    AbstainReason::Unresolved
}

/// Energy bookkeeping: is the total KE accounted (no spontaneous, source-less gain) over the window?
/// We compare early-window vs late-window total KE; a large unforced INCREASE is unaccounted energy.
/// A decrease (dissipation) or flat profile is fine. RELATIVE — uses the same per-window kinematics.
fn energy_accounted(
    t: &Track,
    mass: f32,
    inertia: f32,
    omega: Option<f32>,
    dt_total: f32,
    window: usize,
) -> bool {
    let p_win = momentum_window(t, mass, window);
    if p_win.len() < 3 {
        return true; // not enough to find a contradiction; don't manufacture one.
    }
    // linear KE per step from |p|: KE_lin = |p|²/(2m).
    let ke_lin_series: Vec<f32> = p_win.iter().map(|p| p * p / (2.0 * mass.max(1e-9))).collect();
    // rotational KE: roughly constant within the window from the mean ω (history lacks per-step pts).
    let ke_rot = match (omega, ang_momentum_window(&t.spinor, inertia, dt_total, window)) {
        (Some(_), Some(l_win)) if !l_win.is_empty() => l_win
            .iter()
            .map(|l| l * l / (2.0 * inertia.max(1e-9)))
            .collect::<Vec<_>>(),
        _ => vec![0.0; ke_lin_series.len()],
    };
    let m = ke_lin_series.len().min(ke_rot.len()).max(1);
    let total: Vec<f32> = (0..m)
        .map(|i| ke_lin_series[i] + ke_rot.get(i).copied().unwrap_or(0.0))
        .collect();
    if total.len() < 3 {
        return true;
    }
    let early = total[0];
    let late = *total.last().unwrap();
    // Allow noise + dissipation; flag only a large source-less GAIN (> 50% growth).
    late <= early * 1.5 + 1e-6
}

/// Speed monotonically contracting toward rest over the window (the at-rest precondition, mirroring
/// `physics::speed_contracting`).
fn speed_contracting(t: &Track, window: usize) -> bool {
    let n = t.trajectory.len();
    if n < window + 1 {
        return false;
    }
    let mut prev_speed = f32::INFINITY;
    for k in (n - window)..n {
        let (t1, x1, y1) = t.trajectory[k];
        let (t0, x0, y0) = t.trajectory[k - 1];
        let dt = (t1 - t0).max(1e-3) as f32;
        let s = (((x1 - x0).powi(2) + (y1 - y0).powi(2)).sqrt()) / dt;
        if s > prev_speed + 0.005 {
            return false;
        }
        prev_speed = s;
    }
    true
}

/// Convenience: build a profile straight from a confirmed track, deriving the silhouette descriptor
/// from the track's carried fields (genus/elongation/orientation, aspect from the bbox). `fill` is
/// not tracked frame-to-frame, so a coarse default is used — for the highest-fidelity geometry pass
/// the live `ObjectDescriptor` from the matched proposal to [`profile`] instead (the `intel`
/// subcommand does this). The regime/conservation verdicts do not depend on `fill` (it scales mass
/// and inertia together, cancelling in every ratio test).
pub fn profile_track(t: &Track, c_max: f32, cfg: &IntelConfig) -> RigidProfile {
    profile_track_with_prior(t, c_max, cfg, None)
}

/// As [`profile_track`], but grounded by an optional recon MATERIAL/MASS/INERTIA prior (the recon ->
/// third-eye feedback). When `prior` is `Some`, the mass is `material_density × volume` (the inter-
/// object ratio is material-weighted); when `None`, the relative equal-density fallback is used.
pub fn profile_track_with_prior(
    t: &Track,
    c_max: f32,
    cfg: &IntelConfig,
    prior: Option<&ObjectPrior>,
) -> RigidProfile {
    let aspect = if t.bh > 1e-6 { t.bw / t.bh } else { 1.0 };
    let desc = ObjectDescriptor {
        genus: t.genus,
        fill: 0.6, // coarse default; cancels in every regime ratio (see doc above).
        aspect,
        elongation: t.elongation,
        orientation: t.orientation,
    };
    // Recon depth heuristic (recon::reconstruct): depth = clamp(0.6/aspect, 0.15..0.9).
    let depth = (0.6 / aspect.max(0.25)).clamp(0.15, 0.9);
    profile_with_prior(t, &desc, depth, c_max, cfg, prior)
}

/// A one-line scene summary: counts by regime, e.g. "3 objects: 1 free_rotation, 2 forced".
pub fn scene_summary(profiles: &[RigidProfile]) -> String {
    use std::collections::BTreeMap;
    let mut counts: BTreeMap<&'static str, usize> = BTreeMap::new();
    for p in profiles {
        *counts.entry(p.regime.as_str()).or_default() += 1;
    }
    let n = profiles.len();
    if n == 0 {
        return "0 objects".to_string();
    }
    let parts: Vec<String> = counts.iter().map(|(k, v)| format!("{v} {k}")).collect();
    format!("{n} object{}: {}", if n == 1 { "" } else { "s" }, parts.join(", "))
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::orientation_spinor::wrap_pi2;
    use std::f32::consts::PI;

    /// Build a minimal confirmed track with a synthetic trajectory and spinor for the dynamical
    /// tests. `traj` = (pts,x,y) points; `dirs` = (orientation, elongation) spinor samples.
    fn mk_track(id: u64, traj: Vec<(f64, f32, f32)>, dirs: Vec<(f32, f32)>) -> Track {
        // Seed velocity from the last trajectory step so t.vx()/vy()/speed() are non-trivial.
        let mut t = make_blank_track(id);
        for (i, (pts, x, y)) in traj.iter().enumerate() {
            if i == 0 {
                t.seed_pos(*x, *y, *pts);
            } else {
                t.push_meas(*x, *y, *pts);
            }
        }
        for (ori, elong) in dirs {
            t.spinor.observe(ori, elong);
        }
        t.confirmed = true;
        t.hits = traj.len().max(1) as u32;
        t.misses = 0;
        t
    }

    fn make_blank_track(id: u64) -> Track {
        Track::for_test(id)
    }

    #[test]
    fn izz_factor_is_one_for_round_grows_with_elongation() {
        assert!((izz_shape_factor(1.0) - 1.0).abs() < 1e-6, "round disc factor = 1");
        assert!(izz_shape_factor(3.0) > izz_shape_factor(1.5), "more elongated => larger I_zz factor");
        assert!(izz_shape_factor(5.0) > izz_shape_factor(3.0));
    }

    #[test]
    fn constancy_flat_is_constant_spread_changing_is_not() {
        let (_m, spread, ok) = constancy(&[1.0, 1.01, 0.99, 1.0], 0.25);
        assert!(ok, "flat series is constant, spread {spread}");
        let (_m2, spread2, ok2) = constancy(&[1.0, 2.0, 3.0, 4.0], 0.25);
        assert!(!ok2, "ramping series is not constant, spread {spread2}");
    }

    #[test]
    fn translating_object_certifies_free_translation() {
        // Constant-velocity trajectory: |p| ~ const => free_translation. No rotation (round, low elong).
        let mut traj = Vec::new();
        for k in 0..12 {
            let pts = k as f64 / 30.0;
            traj.push((pts, 0.1 + 0.02 * k as f32, 0.2)); // steady drift in x
        }
        let dirs = vec![(0.0f32, 1.1f32); 12]; // round-ish: elongation ~1.1, rotation untestable
        let t = mk_track(1, traj, dirs);
        let desc = ObjectDescriptor { genus: 0, fill: 0.7, aspect: 1.0, elongation: 1.1, orientation: 0.0 };
        let prof = profile(&t, &desc, 0.5, 1.5, &IntelConfig::default());
        assert_eq!(prof.regime, Regime::FreeTranslation, "facts: {:?}", prof.facts);
        assert!(prof.momentum > 0.0);
    }

    #[test]
    fn rotating_object_certifies_free_rotation() {
        // Stationary centroid (tiny orbit) + steady in-plane spin => L ~ const => free_rotation.
        let n = 60;
        let mut traj = Vec::new();
        let mut dirs = Vec::new();
        for k in 0..n {
            let pts = k as f64 / 30.0;
            // centroid essentially fixed (sub-rest jitter): not "translating".
            traj.push((pts, 0.5 + 0.0005 * (k as f32).sin(), 0.5 + 0.0005 * (k as f32).cos()));
            let phi = 1.0 * 2.0 * PI * (k as f32 / (n - 1) as f32); // one steady physical turn
            dirs.push((wrap_pi2(phi), 6.0f32)); // high elongation => reliable director
        }
        let t = mk_track(2, traj, dirs);
        let desc = ObjectDescriptor { genus: 0, fill: 0.5, aspect: 4.0, elongation: 6.0, orientation: 0.0 };
        let prof = profile(&t, &desc, 0.5, 1.5, &IntelConfig::default());
        assert!(prof.omega.is_some(), "reliable lift => ω present");
        assert_eq!(prof.regime, Regime::FreeRotation, "facts: {:?}", prof.facts);
        assert!(prof.ang_momentum.is_some());
    }

    #[test]
    fn unreliable_lift_abstains_angular() {
        // Low-elongation (blobby) silhouette: director ill-defined => ω abstains, no free_rotation.
        let n = 30;
        let mut traj = Vec::new();
        let mut dirs = Vec::new();
        for k in 0..n {
            let pts = k as f64 / 30.0;
            traj.push((pts, 0.5, 0.5)); // dead still centroid
            let phi = 1.0 * 2.0 * PI * (k as f32 / (n - 1) as f32);
            dirs.push((wrap_pi2(phi), 1.2f32)); // below reliability floor
        }
        let t = mk_track(3, traj, dirs);
        let desc = ObjectDescriptor { genus: 0, fill: 0.8, aspect: 1.0, elongation: 1.2, orientation: 0.0 };
        let prof = profile(&t, &desc, 0.5, 1.5, &IntelConfig::default());
        assert!(prof.omega.is_none(), "unreliable lift => ω abstains (None)");
        assert_ne!(prof.regime, Regime::FreeRotation, "must not certify rotation without a reliable spin");
    }

    #[test]
    fn forced_object_certifies_forced() {
        // Accelerating translation: |p| grows beyond tolerance => momentum NOT conserved => forced.
        let mut traj = Vec::new();
        let mut x = 0.1f32;
        let mut v = 0.01f32;
        for k in 0..14 {
            let pts = k as f64 / 30.0;
            x += v;
            v += 0.004; // accelerate => |p| ramps
            traj.push((pts, x, 0.3));
        }
        let dirs = vec![(0.0f32, 1.1f32); 14];
        let t = mk_track(4, traj, dirs);
        let desc = ObjectDescriptor { genus: 0, fill: 0.6, aspect: 1.0, elongation: 1.1, orientation: 0.0 };
        // Loosen the energy clause is not needed: accelerating gives growing KE, which is exactly the
        // forced signature; but a source-less KE gain would abstain. Acceleration here is the FORCE,
        // so momentum_conserved DECLINES first and net regime is forced (energy gain is accounted by
        // that force). We assert the regime is forced OR abstain (never mislabelled free).
        let prof = profile(&t, &desc, 0.5, 1.5, &IntelConfig::default());
        assert!(
            prof.regime == Regime::Forced || prof.regime == Regime::Abstain,
            "accelerating object must be forced or abstain, got {:?}; facts {:?}",
            prof.regime, prof.facts
        );
        assert_ne!(prof.regime, Regime::FreeTranslation);
    }

    #[test]
    fn non_rigid_actuated_abstain_reads_informatively() {
        // A MOVING track whose per-step momentum has no rigid mean: speed swings wildly (a deforming
        // / actuated body). Momentum spread far exceeds the rigid tolerance => regime Abstain (or
        // Forced), and the abstain-reason classifier reads non_rigid_actuated, not bare abstain.
        let mut traj = Vec::new();
        let mut x = 0.2f32;
        // Bursts of fast motion then dead stops, sustained 3 frames each so the Kalman tracks each
        // regime — the smoothed |v| still swings far beyond the rigid band (a deforming/actuated body
        // has no single rigid momentum over the window). Mirrors the real hand's 148% momentum spread.
        let steps = [
            0.07f32, 0.07, 0.07, // burst
            0.0005, 0.0005, 0.0005, // stop
            0.07, 0.07, 0.07, // burst
            0.0005, 0.0005, 0.0005, // stop
            0.07, 0.07, 0.07,
        ];
        for (k, dx) in steps.iter().enumerate() {
            let pts = k as f64 / 30.0;
            traj.push((pts, x, 0.4));
            x += *dx;
        }
        let dirs = vec![(0.0f32, 1.2f32); steps.len()]; // blobby: angular lift abstains
        let t = mk_track(7, traj, dirs);
        let desc = ObjectDescriptor { genus: 0, fill: 0.6, aspect: 1.0, elongation: 1.2, orientation: 0.0 };
        let prof = profile(&t, &desc, 0.5, 1.5, &IntelConfig::default());
        assert!(prof.momentum_spread > IntelConfig::default().conserve_tol, "spread {:.2} should exceed tol", prof.momentum_spread);
        assert_eq!(
            prof.abstain_reason,
            AbstainReason::NonRigidActuated,
            "moving body, huge momentum spread => non_rigid_actuated; regime {:?} spread {:.2} facts {:?}",
            prof.regime, prof.momentum_spread, prof.facts
        );
    }

    #[test]
    fn clean_free_translation_has_no_abstain_reason() {
        // The free-translation track from the earlier test must annotate as None (nothing to explain).
        let mut traj = Vec::new();
        for k in 0..12 {
            let pts = k as f64 / 30.0;
            traj.push((pts, 0.1 + 0.02 * k as f32, 0.2));
        }
        let dirs = vec![(0.0f32, 1.1f32); 12];
        let t = mk_track(8, traj, dirs);
        let desc = ObjectDescriptor { genus: 0, fill: 0.7, aspect: 1.0, elongation: 1.1, orientation: 0.0 };
        let prof = profile(&t, &desc, 0.5, 1.5, &IntelConfig::default());
        assert_eq!(prof.regime, Regime::FreeTranslation);
        assert_eq!(prof.abstain_reason, AbstainReason::None, "a clean regime needs no abstain reason");
    }

    #[test]
    fn unresolved_when_window_too_short() {
        // Only 2 trajectory points => fewer than the 2 momentum samples the window needs => the
        // conservation test can't run at all => Unresolved (too few held frames), not non-rigid.
        let traj = vec![(0.0, 0.3f32, 0.3f32), (1.0 / 30.0, 0.34, 0.3)];
        let dirs = vec![(0.0f32, 1.2f32); 2];
        let t = mk_track(9, traj, dirs);
        let desc = ObjectDescriptor { genus: 0, fill: 0.6, aspect: 1.0, elongation: 1.2, orientation: 0.0 };
        let prof = profile(&t, &desc, 0.5, 1.5, &IntelConfig::default());
        assert_eq!(prof.regime, Regime::Abstain);
        assert_eq!(prof.abstain_reason, AbstainReason::Unresolved, "short window => unresolved");
    }

    // ===================== RECON -> THIRD-EYE: MATERIAL-GROUNDED MASS =====================

    /// A recon MATERIAL prior grounds the mass: mass = material_density × volume. The SAME translating
    /// track read with a denser prior has a proportionally larger mass and momentum |p| = m·v — the
    /// inter-object ratio is now material-weighted, not the relative DENSITY_GUESS = 1.0.
    #[test]
    fn prior_grounds_mass_and_momentum_by_material_density() {
        let mut traj = Vec::new();
        for k in 0..12 {
            let pts = k as f64 / 30.0;
            traj.push((pts, 0.1 + 0.02 * k as f32, 0.2));
        }
        let dirs = vec![(0.0f32, 1.1f32); 12];
        let t = mk_track(20, traj, dirs);
        let desc = ObjectDescriptor { genus: 0, fill: 0.7, aspect: 1.0, elongation: 1.1, orientation: 0.0 };

        // No prior: relative equal-density (DENSITY_GUESS).
        let bare = profile(&t, &desc, 0.5, 1.5, &IntelConfig::default());
        assert!(!bare.grounded, "no prior => not grounded");
        assert!((bare.density - DENSITY_GUESS).abs() < 1e-6);
        assert_eq!(bare.material, MaterialKind::Unknown);

        // Plastic prior (density 1.2) and a denser prior (3.0): mass scales with density.
        let plastic = ObjectPrior { density: 1.2, material: MaterialKind::Plastic, inertia: None, scale_ref_cm: None };
        let metal = ObjectPrior { density: 3.0, material: MaterialKind::Metal, inertia: None, scale_ref_cm: None };
        let p_plastic = profile(&t, &desc, 0.5, 1.5, &IntelConfig::default());
        let g_plastic = super::profile_with_prior(&t, &desc, 0.5, 1.5, &IntelConfig::default(), Some(&plastic));
        let g_metal = super::profile_with_prior(&t, &desc, 0.5, 1.5, &IntelConfig::default(), Some(&metal));
        let _ = p_plastic;
        assert!(g_plastic.grounded && g_metal.grounded, "priors ground the profiles");
        // Same geometry => volume equal; mass ratio is the density ratio (3.0/1.2 = 2.5).
        assert!((g_plastic.volume - g_metal.volume).abs() < 1e-9, "equal volume");
        let mass_ratio = g_metal.mass / g_plastic.mass;
        assert!((mass_ratio - 2.5).abs() < 1e-3, "mass ratio = density ratio 2.5, got {mass_ratio}");
        // Momentum ratio = mass ratio (same speed) — the grounded inter-object weighting.
        let p_ratio = g_metal.momentum / g_plastic.momentum.max(1e-12);
        assert!((p_ratio - 2.5).abs() < 1e-3, "momentum ratio is the material mass ratio, got {p_ratio}");
        // The grounded mass differs from the relative equal-density mass (the correction).
        assert!((g_metal.mass - bare.mass).abs() > 1e-6, "denser prior changes the mass vs the guess");
    }

    /// A recon-supplied inertia overrides the silhouette estimate (the recon's true voxel inertia is
    /// better than the 2.5D lamina); without it, the silhouette inertia is material-weighted via mass.
    #[test]
    fn prior_inertia_overrides_silhouette_inertia() {
        let n = 60;
        let mut traj = Vec::new();
        let mut dirs = Vec::new();
        for k in 0..n {
            let pts = k as f64 / 30.0;
            traj.push((pts, 0.5 + 0.0005 * (k as f32).sin(), 0.5 + 0.0005 * (k as f32).cos()));
            let phi = 2.0 * PI * (k as f32 / (n - 1) as f32);
            dirs.push((wrap_pi2(phi), 6.0f32));
        }
        let t = mk_track(21, traj, dirs);
        let desc = ObjectDescriptor { genus: 0, fill: 0.5, aspect: 4.0, elongation: 6.0, orientation: 0.0 };
        let prior = ObjectPrior { density: 2.0, material: MaterialKind::Ceramic, inertia: Some(0.0123), scale_ref_cm: None };
        let g = super::profile_with_prior(&t, &desc, 0.5, 1.5, &IntelConfig::default(), Some(&prior));
        assert!((g.inertia_spin - 0.0123).abs() < 1e-6, "recon inertia used: {}", g.inertia_spin);
        // L = I·ω uses the grounded inertia.
        if let (Some(w), Some(l)) = (g.omega, g.ang_momentum) {
            assert!((l - 0.0123 * w).abs() < 1e-5, "L = I_recon · ω");
        }
    }

    /// HONEST SCALE: a prior grounds the inter-object RATIO but NOT absolute SI. Absolute SI is only
    /// admissible when a scale reference is supplied; the prior's `scale_ref_cm` is the gate, and a
    /// prior WITHOUT it leaves absolute SI abstained (the ratio is the only certified quantity).
    #[test]
    fn absolute_si_abstains_without_scale_reference() {
        let no_ref = ObjectPrior { density: 3.0, material: MaterialKind::Metal, inertia: None, scale_ref_cm: None };
        let with_ref = ObjectPrior { density: 3.0, material: MaterialKind::Metal, inertia: None, scale_ref_cm: Some(9.5) };
        assert!(no_ref.scale_ref_cm.is_none(), "no scale ref => absolute SI must stay abstained (ratios only)");
        assert!(with_ref.scale_ref_cm.is_some(), "a scale reference unlocks absolute SI reporting");
        // The grounded mass is the same in both (density × volume) — the scale ref does NOT change the
        // relative mass; it only governs whether absolute units MAY be reported.
        let mut traj = Vec::new();
        for k in 0..12 { traj.push((k as f64 / 30.0, 0.1 + 0.02 * k as f32, 0.2)); }
        let dirs = vec![(0.0f32, 1.1f32); 12];
        let t = mk_track(22, traj, dirs);
        let desc = ObjectDescriptor { genus: 0, fill: 0.7, aspect: 1.0, elongation: 1.1, orientation: 0.0 };
        let a = super::profile_with_prior(&t, &desc, 0.5, 1.5, &IntelConfig::default(), Some(&no_ref));
        let b = super::profile_with_prior(&t, &desc, 0.5, 1.5, &IntelConfig::default(), Some(&with_ref));
        assert!((a.mass - b.mass).abs() < 1e-9, "scale ref does not change the relative mass");
    }

    #[test]
    fn scene_summary_counts_regimes() {
        let mk = |id, regime| RigidProfile {
            id, genus: 0, silhouette_area: 0.1, char_size: 0.1, depth: 0.5, volume: 0.05, mass: 0.05,
            density: DENSITY_GUESS, material: MaterialKind::Unknown, grounded: false,
            inertia_spin: 0.001, vx: 0.0, vy: 0.0, speed: 0.0, momentum: 0.0, ke_lin: 0.0,
            omega: None, ang_momentum: None, ke_rot: None, regime, facts: Vec::new(),
            momentum_spread: f32::INFINITY, ang_spread: None, hold_frames: 0,
            abstain_reason: AbstainReason::None,
        };
        let profs = vec![
            mk(1, Regime::FreeRotation),
            mk(2, Regime::Forced),
            mk(3, Regime::Forced),
        ];
        let s = scene_summary(&profs);
        assert!(s.contains("3 objects"), "{s}");
        assert!(s.contains("1 free_rotation"), "{s}");
        assert!(s.contains("2 forced"), "{s}");
    }
}
